30	export function calculateBasePremium(items: Item[], customer?: { yearsWithMHPCO: number }): number {
31	  const groups = new Map<ItemType, number>();
32	  let totalSurcharge = 0;
33	  for (const item of items) {
34	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
35	    totalSurcharge += itemSurcharge(item);
36	  }
37	
38	  let total = 0;
39	  for (const [type, count] of groups) {
40	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
41	      total += BLOCK_PREMIUM;
42	    } else {
43	      total += count * BASE_PREMIUM[type];
44	    }
45	  }
46	  let policyPremium = total + totalSurcharge;
47	  if (customer && customer.yearsWithMHPCO >= 2) {
48	    policyPremium -= policyPremium * 0.2;
49	  }
50	  return policyPremium;
51	}
